/**
 * A re-export for backwards compatibility with community generators.
 *
 * @deprecated Use the `@prisma/generator` package instead.
 */
export type * from '@prisma/generator'
```

**Key exports:**
- `generatorHandler` - Main function to set up a generator
- `GeneratorError` - Custom error class
- `GeneratorProcess` - Class for spawning/managing generator processes

---

### 2. **Core Handler Interface** (`src/generatorHandler.ts`)

```typescript
import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
import * as JsonRpc from './json-rpc'

export interface Handler {
  onGenerate(options: GeneratorOptions): Promise<any>
  onManifest?(config: GeneratorConfig): GeneratorManifest | Promise<GeneratorManifest>
}

export function generatorHandler(handler: Handler): void {
  const stdinInterface = readline.createInterface({
    input: process.stdin,
    crlfDelay: Infinity,
  })

  stdinInterface.on('line', async (line: string) => {
    const json = JSON.parse(line)

    if (json.method === 'generate' && json.params) {
      try {
        const result = await handler.onGenerate(json.params)
        respond({
          jsonrpc: '2.0',
          result: result,
          id: json.id,
        })
      } catch (_e) {
        const e = _e as Error
        respond({
          jsonrpc: '2.0',
          error: {
            code: -32000,
            message: e.message,
            data: {
              stack: e.stack,
            },
          },
          id: json.id,
        })
      }
    }

    if (json.method === 'getManifest') {
      if (handler.onManifest) {
        try {
          const manifest = await handler.onManifest(json.params)
          respond({
            jsonrpc: '2.0',
            result: {
              manifest,
            },
            id: json.id,
          })
        } catch (_e) {
          const e = _e as Error
          respond({
            jsonrpc: '2.0',
            error: {
              code: -32000,
              message: e.message,
              data: {
                stack: e.stack,
              },
            },
            id: json.id,
          })
        }
      } else {
        respond({
          jsonrpc: '2.0',
          result: {
            manifest: null,
          },
          id: json.id,
        })
      }
    }
  })

  process.stdin.resume()
}

function respond(response: JsonRpc.Response): void {
  process.stderr.write(JSON.stringify(response) + '\n')
}
```

**How the handler works:**
1. Listens on `process.stdin` for JSON-RPC 2.0 requests (line-delimited)
2. Supports two methods: `generate` and `getManifest`
3. Responds via `process.stderr` (JSON-RPC responses)
4. Handles errors with code `-32000` and includes stack traces

---

### 3. **Type Definitions from @prisma/generator** (`packages/generator/src/configuration.ts`)

```typescript
// GeneratorConfig - Configuration for the generator plugin
export interface GeneratorConfig {
  name: string
  output: EnvValue | null
  isCustomOutput?: boolean
  provider: EnvValue
  config: {
    output?: never        // Reserved
    provider?: never      // Reserved
    binaryTargets?: never // Reserved
    previewFeatures?: never // Reserved
  } & {
    [key: string]: string | string[] | undefined
  }
  binaryTargets: BinaryTargetsEnvValue[]
  previewFeatures: string[]
  sourceFilePath: string
}

export interface EnvValue {
  fromEnvVar: null | string
  value: null | string
}

export interface BinaryTargetsEnvValue {
  fromEnvVar: string | null
  value: string
  native?: boolean
}

// GeneratorOptions - Full context passed to onGenerate
export type GeneratorOptions = {
  generator: GeneratorConfig
  otherGenerators: GeneratorConfig[]
  schemaPath: string
  dmmf: DMMF.Document
  datasources: DataSource[]
  datamodel: string
  version: string // version hash
  binaryPaths?: BinaryPaths
  noHints?: boolean
  allowNoModels?: boolean
  typedSql?: SqlQueryOutput[]
}

// GeneratorManifest - Metadata about the generator
export type GeneratorManifest = {
  prettyName?: string
  defaultOutput?: string
  denylists?: {
    models?: string[]
