export async function buildClient({...}): Promise<BuildClientResult> {
  // Creates 5 different client variants
  const nodeClient = new TSClient(nodeClientOptions)
  const defaultClient = new TSClient({...nodeClientOptions, reusedJs: '.'})
  const trampolineTsClient = new TSClient({...nodeClientOptions, reusedJs: '#main-entry-point'})
  const wasmClient = new TSClient({...baseClientOptions, edge: true, wasm: true})

  // Generate files for each variant
  const fileMap: FileMap = {}
  fileMap['index.js'] = JS(nodeClient)
  fileMap['index.d.ts'] = TS(nodeClient)
  fileMap['default.js'] = JS(defaultClient)
  fileMap['default.d.ts'] = TS(defaultClient)
  fileMap['index-browser.js'] = BrowserJS(nodeClient)
  fileMap['edge.js'] = JS(wasmClient)
  fileMap['edge.d.ts'] = TS(wasmClient)

  // Create package.json with complex exports map
  fileMap['package.json'] = JSON.stringify(pkgJson, null, 2)

  // Add preambles to generated files
  addPreambleToJSFiles(fileMap)

  return { fileMap, prismaClientDmmf: dmmf }
}
