const tsNoCheckPreamble = `// @ts-nocheck \n`

export function addPreambleToSourceFiles(fileMap: FileMap, includeTSNoCheckPreamble: Boolean) {
  for (const [key, value] of Object.entries(fileMap)) {
    if ((typeof value === 'string' || Buffer.isBuffer(value)) && extensions.some((ext) => key.endsWith(ext))) {
      fileMap[key] = generatedCodePreamble + (includeTSNoCheckPreamble ? tsNoCheckPreamble : '') + value.toString()
    } else if (typeof value === 'object' && value !== null && !Buffer.isBuffer(value)) {
      addPreambleToSourceFiles(value, includeTSNoCheckPreamble)
    }
  }
}
```

### 4. **`package.json` Structure - `bin` Field and Dependencies**

**TS Generator - package.json:**

```json
{
  "name": "@prisma/client-generator-ts",
  "version": "0.0.0",
  "description": "This package is intended for Prisma's internal use",
  "main": "dist/index.js",
  "module": "dist/index.mjs",
  "types": "dist/index.d.ts",
  "exports": {
    ".": {
      "require": {
        "types": "./dist/index.d.ts",
        "default": "./dist/index.js"
      },
      "import": {
        "types": "./dist/index.d.mts",
        "default": "./dist/index.mjs"
      }
    }
  },
  "dependencies": {
    "@antfu/ni": "0.21.12",
    "@prisma/client-common": "workspace:*",
    "@prisma/debug": "workspace:*",
    "@prisma/dmmf": "workspace:*",
    "@prisma/engines-version": "7.6.0-1.75cbdc1eb7150937890ad5465d861175c6624711",
    "@prisma/fetch-engine": "workspace:*",
    "@prisma/generator": "workspace:*",
    "@prisma/get-platform": "workspace:*",
    "@prisma/internals": "workspace:*",
    "@prisma/param-graph-builder": "workspace:*",
    "@prisma/ts-builders": "workspace:*",
    "fast-glob": "3.3.3",
    "get-tsconfig": "4.10.0",
    "indent-string": "4.0.0",
    "klona": "2.0.6",
    "package-up": "5.0.0",
    "pluralize": "8.0.0",
    "ts-pattern": "5.6.2"
  },
  "scripts": {
    "dev": "DEV=true tsx helpers/build.ts",
    "build": "tsx helpers/build.ts",
    "prepublishOnly": "pnpm run build",
    "test": "vitest run --testTimeout 30000"
  },
  "files": ["dist"],
  "sideEffects": false
}
```

**JS Generator - package.json:**

Similar structure but includes `env-paths` dependency instead of `get-tsconfig`:
```json
{
  "dependencies": {
    "env-paths": "2.2.1",
    // ... same as TS generator otherwise
  }
}
```

**Note:** Neither generator has a `bin` field because they are not CLI tools themselves - they are used as generator libraries by Prisma CLI.

### 5. **`tsconfig.json` and `tsconfig.build.json` Structure**

**tsconfig.json:**
```json
{
  "extends": "../../tsconfig.json",
  "include": ["./**/*"]
}
```
(Both TS and JS generators have identical tsconfig.json)

**tsconfig.build.json:**
```json
{
  "extends": "../../tsconfig.build.regular.json",
  "compilerOptions": {
    "outDir": "dist",
    "rootDir": "src"
  },
  "include": ["src"]
}
```
(Both TS and JS generators have identical tsconfig.build.json)

**Root tsconfig.build.regular.json:**
```json
{
  "compilerOptions": {
    "target": "ES2022",
    "module": "commonjs",
    "lib": ["ES2022", "DOM"],
    "esModuleInterop": true,
    "isolatedModules": true,
    "sourceMap": true,
    "declaration": true,
    "strict": true,
    "noImplicitAny": false,
    "noUncheckedIndexedAccess": false,
    "noImplicitReturns": true,
    "noFallthroughCasesInSwitch": true,
    "useUnknownInCatchVariables": false,
    "skipDefaultLibCheck": true,
    "skipLibCheck": true,
    "emitDeclarationOnly": true,
    "resolveJsonModule": true
  },
  "exclude": ["**/tests", "**/__tests__", "./sandbox", "**/dist", "**/.prisma/client", ...]
}
```

### 6. **The `helpers/build.ts` File Pattern**

**Both generators use identical build.ts:**
```typescript
// packages/client-generator-ts/helpers/build.ts
// packages/client-generator-js/helpers/build.ts
import { build } from '../../../helpers/compile/build'
import { adapterConfig } from '../../../helpers/compile/configs'

void build(adapterConfig)
```

**Build Configuration - helpers/compile/build.ts:**

Uses esbuild with plugins:
```typescript
export async function build(options: BuildOptions[]) {
  return transduce.async(
    createBuildOptions(options),
    pipe.async(computeOptions, logStartBuild, addExtensionFormat, addDefaultOutDir, executeEsBuild),
  )
}

// Builds both CJS and ESM formats
async function executeEsBuild(options: BuildOptions) {
  if (process.env.WATCH === 'true') {
    const context = await esbuild.context(options)
    watch(context, options)
  }
  const build = await esbuild.build(options)
  // Write metafile if requested
}
```

**Adapter Config - helpers/compile/configs.ts:**
```typescript
export const adapterConfig = createAdapterConfig([
  { entry: 'src/index.ts', outfile: 'dist/index' }
])

function createAdapterConfig(entries: AdapterEntry[]): BuildOptions[] {
  return entries.flatMap(({ entry, outfile }) => [
    {
      name: `${baseName}-cjs`,
      format: 'cjs' as const,
      bundle: true,
      entryPoints: [entry],
      outfile,
      emitTypes: true,
    },
    {
      name: `${baseName}-esm`,
      format: 'esm' as const,
      bundle: true,
      entryPoints: [entry],
      outfile,
      outExtension: { '.js': '.mjs' },
      emitTypes: true,
    },
  ])
}
```

### 7. **How `onGenerate` Callback Is Implemented**

The generators implement the `generate()` method from the `Generator` interface, which is called for each generation:

**TS Generator:**
```typescript
export class PrismaClientTsGenerator implements Generator {
  readonly name = 'prisma-client-ts'

  async getManifest(config: GeneratorConfig): Promise<GeneratorManifest> {
    return Promise.resolve({
      defaultOutput: getOutputPath(config),
      prettyName: 'Prisma Client',
      version: clientVersion,
      requiresEngines: [],
      requiresEngineVersion: enginesVersion,
    })
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const { config } = options.generator
    const outputDir = getOutputPath(options.generator)
    const tsconfig = getTsconfig(outputDir)?.config

    // Parse configuration options
    const target = config.runtime !== undefined 
      ? parseRuntimeTargetFromUnknown(config.runtime) 
      : 'nodejs'

    const generatedFileExtension = parseGeneratedFileExtension(...)
    const importFileExtension = parseImportFileExtension(...)
    const moduleFormat = parseModuleFormatFromUnknown(...)

    // Call generateClient with all resolved options
    await generateClient({
      datamodel: options.datamodel,
      schemaPath: options.schemaPath,
      binaryPaths: options.binaryPaths!,
      datasources: options.datasources,
      outputDir,
      runtimeBase: '@prisma/client/runtime',
      dmmf: options.dmmf,
      generator: options.generator,
      engineVersion: options.version,
      clientVersion,
      activeProvider: options.datasources[0]?.activeProvider,
      typedSql: options.typedSql,
      target,
      generatedFileExtension,
      importFileExtension,
      moduleFormat,
      tsNoCheckPreamble: true,
      compilerBuild: parseCompilerBuildFromUnknown(options.generator.config.compilerBuild, target),
    })
  }
}
```

**JS Generator:**
```typescript
export class PrismaClientJsGenerator implements Generator {
  readonly name = BuiltInProvider.PrismaClientJs

  constructor(options?: PrismaClientJsGeneratorOptions) {
    this.#shouldResolvePrismaClient = options?.shouldResolvePrismaClient ?? true
    this.#runtimePath = options?.runtimePath
  }

  async getManifest(config: GeneratorConfig): Promise<GeneratorManifest> {
    const defaultOutput = this.#shouldResolvePrismaClient 
      ? await this.#getPrismaClientPath(config) 
      : '.prisma/client'

    return {
      defaultOutput,
      prettyName: 'Prisma Client',
      version: clientVersion,
      requiresEngines: [],
      requiresEngineVersion: enginesVersion,
    }
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = parseEnvValue(options.generator.output!)

    await generateClient({
      datamodel: options.datamodel,
      schemaPath: options.schemaPath,
      binaryPaths: options.binaryPaths!,
      datasources: options.datasources,
      outputDir,
      copyRuntime: Boolean(options.generator.config.copyRuntime),
      copyRuntimeSourceMaps: Boolean(process.env.PRISMA_COPY_RUNTIME_SOURCEMAPS),
      runtimeSourcePath: await this.#getRuntimePath(options.generator),
      dmmf: options.dmmf,
      generator: options.generator,
      engineVersion: options.version,
      clientVersion,
      activeProvider: options.datasources[0]?.activeProvider,
      typedSql: options.typedSql,
      compilerBuild: parseCompilerBuildFromUnknown(options.generator.config.compilerBuild),
    })
  }
}
```

---

### Key Differences Between TS and JS Generators

| Aspect | TS Generator | JS Generator |
|--------|-------------|-------------|
| **Name** | `prisma-client-ts` | `prisma-client-js` |
| **Output** | Single TypeScript bundle | Multiple variants (node, browser, edge) + package.json |
| **Runtime** | Fixed: `@prisma/client/runtime` | Configurable, can copy runtime files |
| **Options** | `target`, `generatedFileExtension`, `importFileExtension`, `moduleFormat` | `copyRuntime`, `copyRuntimeSourceMaps`, `runtimeSourcePath` |
| **Files Generated** | Client, browser, enums, models, internal files | index.js, index.d.ts, default.js, edge.js, browser, package.json, WASM loaders |
| **Client Variants** | 1 main variant | 5 variants (node, default, browser, edge, wasm) |
| **Package.json** | Generated (JS only) | Yes, with complex exports map |

### File Structure of Generated Output

**TS Generator Output:**
```
output-dir/
├── client.ts
├── browser.ts
├── enums.ts
├── commonInputTypes.ts
├── models.ts
└── models/
    ├── User.ts
    ├── Post.ts
    └── ...
└── internal/
    ├── prismaNamespace.ts
    ├── prismaNamespaceBrowser.ts
    └── class.ts
```

**JS Generator Output:**
```
output-dir/
├── index.js
├── index.d.ts
├── index-browser.js
├── default.js
├── default.d.ts
├── client.js
├── client.d.ts
├── edge.js
├── edge.d.ts
├── package.json
├── wasm-worker-loader.mjs
├── wasm-edge-light-loader.mjs
└── sql/
    └── index.js
```

---

**Key File Paths for Reference:**

- `/packages/client-generator-ts/src/index.ts` - Entry point
- `/packages/client-generator-ts/src/generator.ts` - Generator implementation
- `/packages/client-generator-ts/src/generateClient.ts` - Main client generation logic
- `/packages/client-generator-ts/src/TSClient/TSClient.ts` - File generation orchestration
- `/packages/client-generator-ts/src/dmmf.ts` - DMMF helper class
- `/packages/generator-helper/src/generatorHandler.ts` - Handler for JSON-RPC communication
- `/packages/generator/src/generator.ts` - Generator interface definition
- `/helpers/compile/build.ts` - Build orchestration with esbuild
- `/helpers/compile/configs.ts` - Build configuration

