import type { DMMF } from '@prisma/generator-helper'

/**
 * Maps a Prisma scalar type name to its TypeScript equivalent.
 * Returns `unknown` for any unrecognised type so the output still compiles.
 */
function prismaScalarToTs(typeName: string): string {
  switch (typeName) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      return 'Buffer'
    default:
      return 'unknown'
  }
}

/**
 * Returns the TypeScript type string for a DMMF field, including list and
 * nullability wrappers.
 *
 * - `object` fields resolve to the related model name (useful for nested
 *   types in generated method signatures).
 * - `enum` fields resolve to the enum name.
 * - `unsupported` and unrecognised scalars fall back to `unknown`.
 */
export function prismaTypeToTs(field: DMMF.Field): string {
  let base: string

  if (field.kind === 'scalar') {
    base = prismaScalarToTs(field.type)
  } else if (field.kind === 'enum' || field.kind === 'object') {
    base = field.type
  } else {
    base = 'unknown'
  }

  const typed = field.isList ? `Array<${base}>` : base
  return field.isRequired ? typed : `${typed} | null`
}

/** Lowercases the first character of a string. */
function toLowerFirst(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

/**
 * Returns the REST URL path segment for a model name.
 * Uses a simple lowercase + trailing-s heuristic (e.g. `User` → `users`).
 */
function toUrlPath(modelName: string): string {
  return toLowerFirst(modelName) + 's'
}

/** Returns the generated-file preamble comment. */
export function fileHeader(): string {
  return `/* !!! This is code generated by @prisma/generator-rest-client. Do not edit directly. !!! */
/* eslint-disable */
// biome-ignore-all lint: generated file
`
}

/**
 * Generates a TypeScript interface for the given Prisma model.
 *
 * Only scalar and enum fields are included; relation fields (`kind === 'object'`)
 * are omitted to avoid circular type references across models.
 */
export function generateModelInterface(model: DMMF.Model): string {
  const lines = model.fields
    .filter((f) => f.kind === 'scalar' || f.kind === 'enum')
    .map((f) => `  ${f.name}: ${prismaTypeToTs(f)}`)

  return `export interface ${model.name} {\n${lines.join('\n')}\n}\n`
}

/**
 * Generates a typed CRUD client class for the given Prisma model.
 *
 * Each method maps to a conventional REST verb:
 * - `findMany`   → GET    /<model-plural>
 * - `findUnique` → GET    /<model-plural>/:id
 * - `create`     → POST   /<model-plural>
 * - `update`     → PATCH  /<model-plural>/:id
 * - `delete`     → DELETE /<model-plural>/:id
 */
export function generateModelClient(model: DMMF.Model): string {
  const idField = model.fields.find((f) => f.isId)
  const idName = idField?.name ?? 'id'
  const idType = idField ? prismaTypeToTs(idField) : 'unknown'
  const urlPath = toUrlPath(model.name)

  return `export class ${model.name}Client {
  constructor(private readonly baseUrl: string) {}

  async findMany(params?: { skip?: number; take?: number }): Promise<${model.name}[]> {
    const query = params ? \`?\${new URLSearchParams(params as Record<string, string>).toString()}\` : ''
    const response = await fetch(\`\${this.baseUrl}/${urlPath}\${query}\`)
    return response.json() as Promise<${model.name}[]>
  }

