 * per model as a named property, all sharing the same `baseUrl`.
 *
 * Usage example:
 * ```ts
 * const client = new RestClient('https://api.example.com')
 * const users = await client.user.findMany()
 * ```
 */
export function generateRestClient(models: readonly DMMF.Model[]): string {
  const properties = models.map((m) => `  readonly ${toLowerFirst(m.name)}: ${m.name}Client`).join('\n')

  const assignments = models.map((m) => `    this.${toLowerFirst(m.name)} = new ${m.name}Client(baseUrl)`).join('\n')

  return `export class RestClient {
${properties}

  constructor(baseUrl: string) {
